ALTER TABLE public.athlete_lab_nodes_phase1c_backup ADD CONSTRAINT alb_phase1c_unique UNIQUE (node_id, source_column), ADD CONSTRAINT alb_phase1c_disposition_chk CHECK (disposition IN ('dead','collapsed','relocated','partial_strip')), ADD CONSTRAINT alb_phase1c_pattern_chk CHECK (audit_pattern IN ('pattern_1_dead_doc_drift','pattern_2_mmpose_obsolete','pattern_3_auto_derived_drift','pattern_4_config_overflow')), ADD CONSTRAINT alb_phase1c_slice_chk CHECK (slice IN ('B','C','D','E')); CREATE INDEX IF NOT EXISTS alb_phase1c_node_idx ON public.athlete_lab_nodes_phase1c_backup (node_id);